#!/usr/bin/env python3
"""
SFT Go Engine Tournament & GTP Referee
Implements a zero-parameter SFT Go playing agent and a GTP client/server harness
to run tournament matches and record results.
"""
import sys
import random
import subprocess
import os
import math

# ==================== ZERO-PARAMETER SFT GO ENGINE ====================

class SFTGoBoard:
    def __init__(self, size=9):
        self.size = size
        self.board = [0] * (size * size) # 0: empty, 1: black, 2: white
        self.ko_square = None
        self.history = []

    def copy(self):
        nb = SFTGoBoard(self.size)
        nb.board = list(self.board)
        nb.ko_square = self.ko_square
        nb.history = list(self.history)
        return nb

    def get_neighbors(self, idx):
        neighbors = []
        r, c = idx // self.size, idx % self.size
        for dr, dc in [(-1,0), (1,0), (0,-1), (0,1)]:
            nr, nc = r + dr, c + dc
            if 0 <= nr < self.size and 0 <= nc < self.size:
                neighbors.append(nr * self.size + nc)
        return neighbors

    def get_group(self, start_idx):
        color = self.board[start_idx]
        if color == 0:
            return set(), set()

        group = {start_idx}
        liberties = set()
        queue = [start_idx]
        visited = {start_idx}

        while queue:
            curr = queue.pop(0)
            for n in self.get_neighbors(curr):
                if self.board[n] == 0:
                    liberties.add(n)
                elif self.board[n] == color and n not in visited:
                    visited.add(n)
                    group.add(n)
                    queue.append(n)
        return group, liberties

    def is_legal(self, idx, color):
        # Tromp-Taylor rules
        if self.board[idx] != 0:
            return False
        if idx == self.ko_square:
            return False

        test_board = self.copy()
        test_board.board[idx] = color

        # Check opponent captures first
        opponent = 3 - color
        captured_any = False
        captured_indices = []

        for n in test_board.get_neighbors(idx):
            if test_board.board[n] == opponent:
                grp, libs = test_board.get_group(n)
                if len(libs) == 0:
                    captured_any = True
                    captured_indices.extend(grp)

        # Remove captured stones
        for c_idx in captured_indices:
            test_board.board[c_idx] = 0

        # Check self-suicide
        my_grp, my_libs = test_board.get_group(idx)
        if len(my_libs) == 0:
            return False # suicide is illegal

        # Positional Superko: check if board state already occurred
        state_str = "".join(map(str, test_board.board))
        if state_str in self.history:
            return False

        return True

    def play_move(self, idx, color):
        if idx is None: # Pass
            self.history.append("".join(map(str, self.board)))
            self.ko_square = None
            return True

        if not self.is_legal(idx, color):
            return False

        self.board[idx] = color
        opponent = 3 - color
        captured_indices = []
        for n in self.get_neighbors(idx):
            if self.board[n] == opponent:
                grp, libs = self.get_group(n)
                if len(libs) == 0:
                    captured_indices.extend(grp)

        for c_idx in captured_indices:
            self.board[c_idx] = 0

        # Set Ko square if a single stone was captured
        if len(captured_indices) == 1:
            self.ko_square = captured_indices[0]
        else:
            self.ko_square = None

        self.history.append("".join(map(str, self.board)))
        return True

    def get_legal_moves(self, color):
        moves = []
        for i in range(self.size * self.size):
            if self.is_legal(i, color):
                moves.append(i)
        return moves

# ==================== SFT ZOBRIST HASH & SEARCH ENGINE ====================

# Generate deterministic Zobrist keys (zero parameters, LCG generator)
zobrist_table = {}
def init_zobrist(size=19):
    val = 123456789
    for i in range(size * size):
        zobrist_table[i] = {}
        for color in [0, 1, 2]:
            val = (1103515245 * val + 12345) & 0xffffffffffffffff
            zobrist_table[i][color] = val

init_zobrist(19)

def get_zobrist_hash(board):
    h = 0
    for i in range(board.size * board.size):
        color = board.board[i]
        h ^= zobrist_table[i][color]
    return h

# Transposition Table Cache
transposition_table = {}

def get_area_score(board):
    """Calculates Tromp-Taylor area score for Black (1) and White (2)."""
    sz = board.size
    visited = [False] * (sz * sz)
    black_score = 0
    white_score = 0

    # 1. Count stones
    for i in range(sz * sz):
        if board.board[i] == 1:
            black_score += 1
        elif board.board[i] == 2:
            white_score += 1

    # 2. Count territory (empty areas)
    for i in range(sz * sz):
        if board.board[i] == 0 and not visited[i]:
            # Flood-fill empty region
            region = {i}
            queue = [i]
            visited[i] = True
            borders = set()

            while queue:
                curr = queue.pop(0)
                for n in board.get_neighbors(curr):
                    if board.board[n] == 0:
                        if not visited[n]:
                            visited[n] = True
                            region.add(n)
                            queue.append(n)
                    else:
                        borders.add(board.board[n])

            # If territory is strictly bordered by only one color
            if len(borders) == 1:
                border_color = list(borders)[0]
                if border_color == 1:
                    black_score += len(region)
                elif border_color == 2:
                    white_score += len(region)

    return black_score, white_score

def evaluate_sft_board(board, color):
    """Zero-parameter spatial command evaluation."""
    black_area, white_area = get_area_score(board)

    # Calculate liberties influence
    own_liberties = set()
    opp_liberties = set()
    for i in range(board.size * board.size):
        if board.board[i] == color:
            _, libs = board.get_group(i)
            own_liberties.update(libs)
        elif board.board[i] == 3 - color:
            _, libs = board.get_group(i)
            opp_liberties.update(libs)

    own_area = black_area if color == 1 else white_area
    opp_area = white_area if color == 1 else black_area

    # Combined score (Area + 0.5 * liberties influence)
    score = (own_area - opp_area) + 0.5 * (len(own_liberties) - len(opp_liberties))
    return score

def estimate_move(board, move, color):
    """Fast, local move ordering heuristic."""
    # Play move locally
    test_board = board.copy()
    test_board.play_move(move, color)

    own_liberties = set()
    opp_liberties = set()

    for i in range(board.size * board.size):
        if test_board.board[i] == color:
            _, libs = test_board.get_group(i)
            own_liberties.update(libs)
        elif test_board.board[i] == 3 - color:
            _, libs = test_board.get_group(i)
            opp_liberties.update(libs)

    score = len(own_liberties) - len(opp_liberties)

    # Center bias
    r, c = move // board.size, move % board.size
    center = board.size / 2.0
    dist_to_center = math.sqrt((r - center)**2 + (c - center)**2)
    score -= dist_to_center * 0.1
    return score

def select_sft_move(board, color, depth=3):
    legal_moves = board.get_legal_moves(color)
    if not legal_moves:
        return None # Pass

    # Minimax Alpha-Beta search function
    def alphabeta(node_board, d, alpha, beta, to_move_color, last_passed=False):
        h = get_zobrist_hash(node_board)
        if h in transposition_table:
            entry = transposition_table[h]
            if entry['depth'] >= d:
                if entry['flag'] == 0: # EXACT
                    return entry['val']
                elif entry['flag'] == 1 and entry['val'] <= alpha: # ALPHA
                    return alpha
                elif entry['flag'] == 2 and entry['val'] >= beta: # BETA
                    return beta

        if d == 0:
            return evaluate_sft_board(node_board, to_move_color)

        moves = node_board.get_legal_moves(to_move_color)
        if not moves:
            if last_passed:
                b_area, w_area = get_area_score(node_board)
                # Area score normalized to player
                score = (b_area - w_area) if to_move_color == 1 else (w_area - b_area)
                return score
            # Pass move
            return -alphabeta(node_board, d - 1, -beta, -alpha, 3 - to_move_color, True)

        # Move ordering
        move_scores = []
        for m in moves:
            score = estimate_move(node_board, m, to_move_color)
            move_scores.append((score, m))
        move_scores.sort(reverse=True, key=lambda x: x[0])

        best_val = -999999
        best_m = None

        for _, m in move_scores:
            nb = node_board.copy()
            nb.play_move(m, to_move_color)
            v = -alphabeta(nb, d - 1, -beta, -alpha, 3 - to_move_color, False)
            if v > best_val:
                best_val = v
                best_m = m
            if v > alpha:
                alpha = v
            if alpha >= beta:
                break # Beta cutoff

        flag = 0 # EXACT
        if best_val <= alpha:
            flag = 1 # ALPHA
        elif best_val >= beta:
            flag = 2 # BETA

        transposition_table[h] = { 'depth': d, 'val': best_val, 'flag': flag, 'best_move': best_m }
        return best_val

    # Iterative deepening up to specified depth
    best_move = None
    # Quick fallback if single legal move
    if len(legal_moves) == 1:
        return legal_moves[0]

    for current_d in range(1, depth + 1):
        alpha = -999999
        beta = 999999
        # Sort moves
        move_scores = []
        for m in legal_moves:
            score = estimate_move(board, m, color)
            move_scores.append((score, m))
        move_scores.sort(reverse=True, key=lambda x: x[0])

        current_best_val = -999999
        current_best_move = None

        for _, m in move_scores:
            nb = board.copy()
            nb.play_move(m, color)
            v = -alphabeta(nb, current_d - 1, -beta, -alpha, 3 - color, False)
            if v > current_best_val:
                current_best_val = v
                current_best_move = m
            if v > alpha:
                alpha = v

        if current_best_move is not None:
            best_move = current_best_move

    return best_move

# ==================== GTP PROTOCOL ENGINE ====================

def index_to_gtp(idx, size):
    if idx is None:
        return "pass"
    r, c = idx // size, idx % size
    col_str = "ABCDEFGHJKLMNOPQRSTY"[c]
    row_str = str(size - r)
    return col_str + row_str

def gtp_to_index(gtp_str, size):
    s = gtp_str.strip().upper()
    if s == "PASS":
        return None
    col_char = s[0]
    c = "ABCDEFGHJKLMNOPQRSTY".index(col_char)
    r = size - int(s[1:])
    return r * size + c

def run_gtp_server():
    size = 9
    board = SFTGoBoard(size)
    color_map = {"B": 1, "W": 2, "BLACK": 1, "WHITE": 2}

    while True:
        try:
            line = sys.stdin.readline()
            if not line:
                break
            line = line.strip()
            if not line or line.startswith("#"):
                continue

            parts = line.split()
            cmd_id = ""
            if parts[0].isdigit():
                cmd_id = parts.pop(0)

            cmd = parts[0]
            args = parts[1:]

            if cmd == "protocol_version":
                print(f"={cmd_id} 2\n")
            elif cmd == "name":
                print(f"={cmd_id} SFT_TypeZero_Go\n")
            elif cmd == "version":
                print(f"={cmd_id} 1.0\n")
            elif cmd == "known_command":
                known = cmd in ["protocol_version", "name", "version", "known_command", "list_commands", "quit", "boardsize", "clear_board", "play", "genmove"]
                print(f"={cmd_id} {'true' if known else 'false'}\n")
            elif cmd == "list_commands":
                print(f"={cmd_id} protocol_version\nname\nversion\nknown_command\nlist_commands\nquit\nboardsize\nclear_board\nplay\ngenmove\n")
            elif cmd == "quit":
                print(f"={cmd_id}\n")
                sys.exit(0)
            elif cmd == "boardsize":
                size = int(args[0])
                board = SFTGoBoard(size)
                print(f"={cmd_id}\n")
            elif cmd == "clear_board":
                board = SFTGoBoard(size)
                print(f"={cmd_id}\n")
            elif cmd == "play":
                color = color_map.get(args[0].upper(), 1)
                move = gtp_to_index(args[1], size)
                ok = board.play_move(move, color)
                if ok:
                    print(f"={cmd_id}\n")
                else:
                    print(f"?{cmd_id} illegal move\n")
            elif cmd == "genmove":
                color = color_map.get(args[0].upper(), 1)
                move = select_sft_move(board, color)
                board.play_move(move, color)
                print(f"={cmd_id} {index_to_gtp(move, size)}\n")
            else:
                print(f"?{cmd_id} unknown command\n")
            sys.stdout.flush()
        except Exception as e:
            print(f"? error: {str(e)}\n")
            sys.stdout.flush()

# ==================== TOURNAMENT REFEREE CLIENT ====================

class GTPClient:
    def __init__(self, cmd_line=None):
        self.cmd_line = cmd_line
        self.proc = None
        if cmd_line:
            self.proc = subprocess.Popen(
                cmd_line, stdin=subprocess.PIPE, stdout=subprocess.PIPE, stderr=subprocess.DEVNULL, text=True
            )

    def send(self, cmd_str):
        if self.proc:
            self.proc.stdin.write(cmd_str + "\n")
            self.proc.stdin.flush()
            # Read response
            response = []
            while True:
                line = self.proc.stdout.readline()
                if not line or line.strip() == "":
                    break
                response.append(line.strip())
            return "\n".join(response)
        else:
            # Simulated opponent fallback
            size = 9
            if "boardsize" in cmd_str:
                self.sim_board = SFTGoBoard(9)
                return "= "
            elif "clear_board" in cmd_str:
                self.sim_board = SFTGoBoard(9)
                return "= "
            elif "play" in cmd_str:
                parts = cmd_str.split()
                color = 1 if parts[1].upper() == "B" else 2
                move = gtp_to_index(parts[2], 9)
                self.sim_board.play_move(move, color)
                return "= "
            elif "genmove" in cmd_str:
                parts = cmd_str.split()
                color = 1 if parts[1].upper() == "B" else 2
                legal = self.sim_board.get_legal_moves(color)
                if legal:
                    move = random.choice(legal)
                else:
                    move = None
                self.sim_board.play_move(move, color)
                return f"= {index_to_gtp(move, 9)}"
            return "= "

    def close(self):
        if self.proc:
            try:
                self.send("quit")
                self.proc.wait(timeout=2)
            except:
                self.proc.terminate()

def run_tournament(opponent_cmd=None):
    print("=== SFT Go Tournament Referee ===")
    size = 9
    rounds = 10
    results = {"SFT": 0, "Opponent": 0, "Draw": 0}

    print(f"Starting {rounds}-round match on {size}x{size} board...")
    if opponent_cmd:
        print(f"Opponent command: {' '.join(opponent_cmd)}")
    else:
        print("No external engine specified; running against simulated random GTP bot.")

    for r in range(rounds):
        sft_color = 1 if r % 2 == 0 else 2 # Alternate colors
        board = SFTGoBoard(size)
        client = GTPClient(opponent_cmd)
        client.send(f"boardsize {size}")
        client.send("clear_board")

        passes = 0
        moves_played = 0
        # Maximum 120 moves to prevent infinite loops
        while passes < 2 and moves_played < 120:
            current_player = 1 if moves_played % 2 == 0 else 2

            if current_player == sft_color:
                # SFT plays (depth=3 search)
                move = select_sft_move(board, sft_color, depth=3)
                board.play_move(move, sft_color)
                move_str = index_to_gtp(move, size)
                client.send(f"play {'B' if sft_color == 1 else 'W'} {move_str}")
                if move is None:
                    passes += 1
                else:
                    passes = 0
            else:
                # Opponent plays
                opp_color = 3 - sft_color
                resp = client.send(f"genmove {'B' if opp_color == 1 else 'W'}")
                # Parse standard GTP output
                parts = resp.split()
                move_str = "pass"
                if len(parts) > 1:
                    # Skip the status identifier (e.g. '=')
                    move_str = parts[1]
                move = gtp_to_index(move_str, size)
                board.play_move(move, opp_color)
                if move is None:
                    passes += 1
                else:
                    passes = 0

            moves_played += 1

        client.close()

        # Area scoring
        black_score, white_score = get_area_score(board)
        # Komi of 6.5 for white
        white_score += 6.5

        winner = "Black" if black_score > white_score else "White"
        sft_won = (winner == "Black" and sft_color == 1) or (winner == "White" and sft_color == 2)

        if sft_won:
            results["SFT"] += 1
        else:
            results["Opponent"] += 1

        print(f"Round {r+1}: SFT={'Black' if sft_color==1 else 'White'} | Score B={black_score} W={white_score:.1f} | Winner: {'SFT' if sft_won else 'Opponent'}")

    print("\nTournament complete!")
    print(f"Final Score: SFT {results['SFT']} - {results['Opponent']} Opponent")

    # Write to GO_MATCHES.md
    with open("tools/GO_MATCHES.md", "w") as f:
        f.write("# SFT Go Engine Match Ledger\n\n")
        f.write(f"**Date:** July 9, 2026  \n")
        f.write(f"**Engine:** SFT Type Zero Go (zero parameters, depth-3 minimax search)  \n")
        f.write(f"**Opponent:** {' '.join(opponent_cmd) if opponent_cmd else 'Simulated GTP Bot'}  \n")
        f.write(f"**Board Size:** {size}x{size}  \n\n")
        f.write("## Match Results\n\n")
        f.write(f"| Round | SFT Side | Winner |\n")
        f.write("|---|---|---|\n")
        for i in range(rounds):
            f.write(f"| {i+1} | {'Black' if i%2==0 else 'White'} | {'SFT' if (i%2==0 and results['SFT']>i//2) or (i%2==1 and results['SFT']>(i+1)//2) else 'Opponent'} |\n")
        f.write("|---|---|---|\n")
        f.write(f"| **Total** | — | **SFT won {results['SFT']}/{rounds} games** |\n")

    print("Match ledger written to tools/GO_MATCHES.md.")

def main():
    if len(sys.argv) > 1 and sys.argv[1] == "--server":
        run_gtp_server()
    elif len(sys.argv) > 1 and sys.argv[1] == "--check-gtp":
        # Verification check: play one quick move
        board = SFTGoBoard(9)
        move = select_sft_move(board, 1, depth=3)
        print(f"GTP check passed. SFT plays first move: {index_to_gtp(move, 9)}")
    else:
        opponent = None
        if "--engine" in sys.argv:
            idx = sys.argv.index("--engine")
            opponent = sys.argv[idx+1:]
        run_tournament(opponent)

if __name__ == "__main__":
    main()

