import os
import re
import sys

papers_dir = "/Users/mettamazza/Desktop/Smithian Fold Theory/papers"
files = {
    "The_Geometrical_Derivation_of_the_Fine_Structure_Constant.md": [
        "137.03599917718", "34259/250", "5995462/43751", "Maria Smith", "Ernos Labs, Scotland"
    ],
    "A_Winding_Solution_to_the_Hubble_Tension_and_the_Cosmological_Constant.md": [
        "3305/3048", "13/12", "1.0843175", "Maria Smith", "Ernos Labs, Scotland"
    ],
    "Discrete_Regularity_Resolving_Navier_Stokes_via_the_Vorticity_Cap.md": [
        "1/32", "32", "150.000", "Maria Smith", "Ernos Labs, Scotland"
    ]
}

failed = False

for filename, facts in files.items():
    filepath = os.path.join(papers_dir, filename)
    if not os.path.exists(filepath):
        print(f"Error: {filename} does not exist!")
        failed = True
        continue

    with open(filepath, "r") as f:
        content = f.read()

    # 1. Check for unclosed backticks
    unclosed_backticks = content.count("`") % 2 != 0
    if unclosed_backticks:
        print(f"FAIL: {filename} has unclosed backticks!")
        failed = True

    # 2. Check LaTeX brackets
    double_math = content.count("$$") % 2 != 0
    if double_math:
        print(f"FAIL: {filename} has unbalanced double math $$!")
        failed = True

    # 3. Check specific facts
    missing_facts = []
    for fact in facts:
        if fact not in content:
            missing_facts.append(fact)

    if missing_facts:
        print(f"FAIL: {filename} is missing facts: {missing_facts}")
        failed = True
    else:
        print(f"PASS: {filename} (unclosed_backticks={unclosed_backticks}, double_math={double_math}, facts verified)")

if failed:
    sys.exit(1)
else:
    print("All companion preprints passed verification!")
    sys.exit(0)

